={{ `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
body{margin:0;padding:0;background:#f9fafb;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;color:#374151}
.card{max-width:560px;margin:24px auto;background:#fff;border:1px solid #e5e7eb;border-radius:12px;overflow:hidden}
.header{background:#10b981;padding:24px;text-align:center}
.header h1{color:#fff;margin:0;font-size:22px;font-weight:700}
.body{padding:28px}
.greeting{font-size:16px;color:#111827;margin:0 0 8px}
.score-wrap{text-align:center;padding:24px 0}
.score-circle{width:120px;height:120px;border-radius:50%;margin:12px auto;background:conic-gradient(#10b981 0% ${$json.body.score}%,#e5e7eb ${$json.body.score}% 100%);display:flex;align-items:center;justify-content:center}
.score-inner{width:100px;height:100px;border-radius:50%;background:#fff;display:flex;flex-direction:column;align-items:center;justify-content:center}
.score-num{font-size:36px;font-weight:800;line-height:1}
.score-total{font-size:11px;color:#9ca3af;text-transform:uppercase;letter-spacing:1px}
.green{color:#059669}.yellow{color:#d97706}.red{color:#dc2626}
.badge{display:inline-block;padding:4px 14px;border-radius:999px;font-size:12px;font-weight:600;margin:0 4px}
.badge-blue{background:#eff6ff;color:#1d4ed8}
.badge-green{background:#ecfdf5;color:#047857}
.badge-yellow{background:#fefce8;color:#a16207}
.badge-red{background:#fef2f2;color:#b91c1c}
.divider{height:1px;background:#e5e7eb;margin:20px 0}
.footer{text-align:center;font-size:12px;color:#9ca3af;padding:20px 28px;border-top:1px solid #e5e7eb}
</style>
</head>
<body>
<div class="card">
<div class="header"><h1>Postulación Recibida</h1></div>
<div class="body">
<p class="greeting">Hola ${$json.body.candidate_name},</p>
<p style="color:#6b7280">Hemos recibido tu postulación para <strong style="color:#111827">${$json.body.job_title}</strong>.</p>
<div class="score-wrap">
<div class="score-circle">
<div class="score-inner">
<span class="score-num ${$json.body.score >= 75 ? 'green' : ($json.body.score >= 50 ? 'yellow' : 'red')}">${$json.body.score}</span>
<span class="score-total">/ 100</span>
</div>
</div>
</div>
<div style="text-align:center;margin:16px 0">
<span class="badge badge-blue">${$json.body.classification}</span>
<span class="badge ${$json.body.risk_level === 'low' ? 'badge-green' : ($json.body.risk_level === 'medium' ? 'badge-yellow' : 'badge-red')}">Riesgo ${$json.body.risk_level === 'low' ? 'Bajo' : ($json.body.risk_level === 'medium' ? 'Medio' : 'Alto')}</span>
</div>
<div class="divider"></div>
<p style="color:#6b7280">Nuestro equipo de reclutamiento revisará tu perfil y te mantendremos informado sobre el avance de tu candidatura.</p>
</div>
<div class="footer">Gracias por tu interés<br><strong>Equipo de Reclutamiento</strong></div>
</div>
</body>
</html>` }}

={{ `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
body{margin:0;padding:0;background:#f9fafb;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;color:#374151}
.card{max-width:560px;margin:24px auto;background:#fff;border:1px solid #e5e7eb;border-radius:12px;overflow:hidden}
.header{background:#10b981;padding:20px;text-align:center}
.header h1{color:#fff;margin:0;font-size:20px;font-weight:700}
.body{padding:24px}
.field{display:flex;padding:8px 0;border-bottom:1px solid #f3f4f6}
.flabel{width:120px;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:.5px;color:#9ca3af}
.fval{flex:1;font-size:14px;color:#111827}
.badge{display:inline-block;padding:2px 10px;border-radius:999px;font-size:11px;font-weight:600}
.badge-blue{background:#eff6ff;color:#1d4ed8}
.badge-green{background:#ecfdf5;color:#047857}
.badge-yellow{background:#fefce8;color:#a16207}
.badge-red{background:#fef2f2;color:#b91c1c}
.divider{height:1px;background:#e5e7eb;margin:16px 0}
.footer{text-align:center;font-size:12px;color:#9ca3af;padding:16px 24px;border-top:1px solid #e5e7eb}
</style>
</head>
<body>
<div class="card">
<div class="header"><h1>Nuevo Candidato</h1></div>
<div class="body">
<p style="margin-top:0;color:#6b7280">Se ha recibido una nueva postulación.</p>
<div class="field"><span class="flabel">Candidato</span><span class="fval">${$json.body.candidate_name}</span></div>
<div class="field"><span class="flabel">Email</span><span class="fval">${$json.body.candidate_email}</span></div>
<div class="field"><span class="flabel">Vacante</span><span class="fval">${$json.body.job_title}</span></div>
<div class="field"><span class="flabel">Score</span><span class="fval" style="font-weight:700;color:${$json.body.score >= 75 ? '#059669' : ($json.body.score >= 50 ? '#d97706' : '#dc2626')}">${$json.body.score}/100</span></div>
<div class="field"><span class="flabel">Clasificación</span><span class="fval"><span class="badge badge-blue">${$json.body.classification}</span></span></div>
<div class="field"><span class="flabel">Riesgo</span><span class="fval"><span class="badge ${$json.body.risk_level === 'low' ? 'badge-green' : ($json.body.risk_level === 'medium' ? 'badge-green' : 'badge-red')}">${$json.body.risk_level === 'low' ? 'Bajo' : ($json.body.risk_level === 'medium' ? 'Medio' : 'Alto')}</span></span></div>
<div class="divider"></div>
<p style="font-size:13px;color:#6b7280">Revisa los detalles en la plataforma.</p>
</div>
<div class="footer">Equipo de Reclutamiento</div>
</div>
</body>
</html>` }}
